func lis(arr []int) int {
	g := make([]int, 0)
	for _, x := range arr {
		j := sort.SearchInts(g, x)
		if j == len(g) {
			g = append(g, x)
		} else {
			g[j] = x
		}
	}
	return len(g)
}

